<span class="line"><span style="color:#F92672;">elif</span><span style="color:#AE81FF;"> 3</span><span style="color:#F92672;"> &lt;=</span><span style="color:#F8F8F2;"> month </span><span style="color:#F92672;">&lt;=</span><span style="color:#AE81FF;"> 5</span><span style="color:#F8F8F2;">:</span></span>
